import React, { useState } from 'react';
import Icon from '../../components/Icon';
import { useAuth } from '../../context/AuthContext';
import { checkPasswordStrength } from '../../utils/helpers';

export default function LoginPage({ switchTo }) {
  const { login, authenticate } = useAuth();
  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [showPwd,  setShowPwd]  = useState(false);
  const [remember, setRemember] = useState(false);
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState("");
  const [errors,   setErrors]   = useState({});

  const validate = () => {
    const e = {};
    if (!email.trim())    e.email    = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) e.email = "Enter a valid email address";
    if (!password)        e.password = "Password is required";
    return e;
  };

  const handleSubmit = async () => {
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setErrors({}); setError(""); setLoading(true);
    await new Promise(r => setTimeout(r, 1000));
    try {
      const user = authenticate(email, password);
      login(user);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDemo = async () => {
    setLoading(true);
    await new Promise(r => setTimeout(r, 700));
    login({ id: "demo", name: "Demo User", firstName: "Demo", lastName: "User", email: "demo@stockiq.in", role: "premium", plan: "Premium", joinedAt: new Date().toISOString() });
  };

  const handleKeyDown = (e) => { if (e.key === "Enter") handleSubmit(); };

  return (
    <div className="auth-card">
      <div className="auth-card-title">Welcome back</div>
      <div className="auth-card-sub">
        Don't have an account? <a onClick={() => switchTo("register")}>Create one free →</a>
      </div>

      {error && <div className="auth-alert danger"><Icon name="alert" size={15} />{error}</div>}

      {/* Email */}
      <div className="form-group">
        <label className="form-label">Email Address</label>
        <div className="field-wrap">
          <input className={`field-input${errors.email ? " error" : ""}`} type="email" placeholder="you@example.com" value={email} onChange={e => { setEmail(e.target.value); setErrors(x => ({...x, email: ""})); }} onKeyDown={handleKeyDown} autoComplete="email" />
          <span className="field-icon"><Icon name="mail" size={15} /></span>
        </div>
        {errors.email && <div className="field-error"><Icon name="alert" size={13} />{errors.email}</div>}
      </div>

      {/* Password */}
      <div className="form-group">
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <label className="form-label" style={{ margin: 0 }}>Password</label>
          <button className="forgot-link" onClick={() => switchTo("forgot")}>Forgot password?</button>
        </div>
        <div className="field-wrap">
          <input className={`field-input${errors.password ? " error" : ""}`} type={showPwd ? "text" : "password"} placeholder="••••••••" value={password} onChange={e => { setPassword(e.target.value); setErrors(x => ({...x, password: ""})); }} onKeyDown={handleKeyDown} autoComplete="current-password" />
          <span className="field-icon" onClick={() => setShowPwd(v => !v)}>{showPwd ? <Icon name="eyeOff" size={15} /> : <Icon name="eye" size={15} />}</span>
        </div>
        {errors.password && <div className="field-error"><Icon name="alert" size={13} />{errors.password}</div>}
      </div>

      {/* Remember */}
      <div className="form-group">
        <label className="check-label">
          <input type="checkbox" checked={remember} onChange={e => setRemember(e.target.checked)} />
          Keep me signed in for 30 days
        </label>
      </div>

      <button className="btn-submit" onClick={handleSubmit} disabled={loading}>
        {loading ? <><div className="spinner" /> Signing in…</> : <>Sign In <Icon name="arrowRight" size={16} /></>}
      </button>

      <div className="auth-divider">or</div>

      <div className="social-btns">
        <button className="btn-social">
          <svg width="16" height="16" viewBox="0 0 24 24"><path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/><path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>
          Google
        </button>
        <button className="btn-social">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 0C5.37 0 0 5.37 0 12c0 5.31 3.435 9.795 8.205 11.385.6.105.825-.255.825-.57 0-.285-.015-1.23-.015-2.235-3.015.555-3.795-.735-4.035-1.41-.135-.345-.72-1.41-1.23-1.695-.42-.225-1.02-.78-.015-.795.945-.015 1.62.87 1.845 1.23 1.08 1.815 2.805 1.305 3.495.99.105-.78.42-1.305.765-1.605-2.67-.3-5.46-1.335-5.46-5.925 0-1.305.465-2.385 1.23-3.225-.12-.3-.54-1.53.12-3.18 0 0 1.005-.315 3.3 1.23.96-.27 1.98-.405 3-.405s2.04.135 3 .405c2.295-1.56 3.3-1.23 3.3-1.23.66 1.65.24 2.88.12 3.18.765.84 1.23 1.905 1.23 3.225 0 4.605-2.805 5.625-5.475 5.925.435.375.81 1.095.81 2.22 0 1.605-.015 2.895-.015 3.3 0 .315.225.69.825.57A12.02 12.02 0 0 0 24 12c0-6.63-5.37-12-12-12z"/></svg>
          GitHub
        </button>
      </div>

      <div style={{ marginTop: 20, borderTop: "1px solid var(--border)", paddingTop: 16 }}>
        <button className="btn-ghost" style={{ width: "100%", justifyContent: "center" }} onClick={handleDemo}>
          <Icon name="shield" size={14} /> Try Demo Account (Premium)
        </button>
      </div>
    </div>
  );
}
